    pub fn matchRules(self: *BaseLexer) Token {
        while (true) {
            const ws_start = self.pos;
            while (self.pos < self.source.len and (self.source[self.pos] == ' ' or self.source[self.pos] == '\t'))
                self.pos += 1;
            const ws_count: u8 = @intCast(@min(self.pos - ws_start, 255));

            if (self.pos >= self.source.len)
                return Token{ .cat = .eof, .pre = ws_count, .pos = @intCast(self.pos), .len = 0 };


            const start: u32 = @intCast(self.pos);
            self.beg = 0;
            var best_len: usize = 0;
            var best_rule: usize = 72;
            for (dispatch[self.source[self.pos]]) |ri| {
                if (match.matchAt(rules[ri].pat, self.source, self.pos)) |len| {
                    if (len > best_len) {
                        best_len = len;
                        best_rule = ri;
                    }
                }
            }

            if (best_rule < 72) {
                self.pos += @intCast(best_len);
                const rule = rules[best_rule];

                for (rule.acts) |act| {
                    const states = [_]*i32{&self.beg, &self.heredoc, &self.paren, &self.brace, &self.math};
                    switch (act.k) {
                        .set => states[act.v].* = act.n,
                        .inc => states[act.v].* += 1,
                        .dec => states[act.v].* -= 1,
                    }
                }

                if (rule.skip) continue;

                const final_cat = if (rule.tok == .lparen and ws_count == 0) .lparen_tight else rule.tok;
                return Token{ .cat = final_cat, .pre = ws_count, .pos = start, .len = @intCast(best_len) };
            }

            self.pos += 1;
            return Token{ .cat = .err, .pre = ws_count, .pos = start, .len = 1 };
        }
    }
